import io.harbor.textd.core.TextDaemon;
import java.lang.ref.WeakReference;
import java.lang.reflect.Field;
import java.nio.file.Path;
import java.util.ArrayList;
import java.util.List;
import java.util.concurrent.atomic.AtomicReference;

public class LeakProbe {
    public static void main(String[] args) throws Exception {
        Path pluginJar = Path.of(args[0]);
        List<WeakReference<ClassLoader>> refs = new ArrayList<>();
        TextDaemon daemon = new TextDaemon(pluginJar, 4);
        try {
            for (int generation = 1; generation <= 4; generation++) {
                daemon.reload(generation);
                daemon.processBatch(List.of("alpha beta gamma", "alpha beta gamma", "alpha beta gamma", "alpha beta gamma"));
                refs.add(new WeakReference<>(currentLoader(daemon)));
            }
        } finally {
            daemon.close();
        }

        for (int i = 0; i < 5; i++) {
            System.gc();
            Thread.sleep(100);
            System.out.println("after gc " + i + ": alive=" + alive(refs));
        }
    }

    private static int alive(List<WeakReference<ClassLoader>> refs) {
        int alive = 0;
        for (WeakReference<ClassLoader> ref : refs) {
            if (ref.get() != null) {
                alive++;
            }
        }
        return alive;
    }

    private static ClassLoader currentLoader(TextDaemon daemon) throws Exception {
        Field revisionsField = TextDaemon.class.getDeclaredField("revisions");
        revisionsField.setAccessible(true);
        Object revisions = revisionsField.get(daemon);

        Field currentField = revisions.getClass().getDeclaredField("current");
        currentField.setAccessible(true);
        AtomicReference<?> current = (AtomicReference<?>) currentField.get(revisions);
        Object frame = current.get();

        Field loadedField = frame.getClass().getDeclaredField("loadedGeneration");
        loadedField.setAccessible(true);
        Object loaded = loadedField.get(frame);

        Field classLoaderField = loaded.getClass().getDeclaredField("classLoader");
        classLoaderField.setAccessible(true);
        return (ClassLoader) classLoaderField.get(loaded);
    }
}
