            daemon.processBatch(List.of("alpha beta gamma", "alpha beta gamma", "alpha beta gamma", "alpha beta gamma"));
        }
        daemon.close();

        Field threadLocalsField = Thread.class.getDeclaredField("threadLocals");
        threadLocalsField.setAccessible(true);
