        inheritableField.setAccessible(true);
        Field targetField = Thread.class.getDeclaredField("target");
        targetField.setAccessible(true);
        for (Thread thread : Thread.getAllStackTraces().keySet()) {
            if (thread.getName().startsWith("textd-worker-")) {
                System.out.println(thread.getName() + " state=" + thread.getState());
                System.out.println("  contextClassLoader=" + thread.getContextClassLoader());
                System.out.println("  target=" + targetField.get(thread));
                System.out.println("  threadLocals=" + threadLocalsField.get(thread));
                System.out.println("  inheritableThreadLocals=" + inheritableField.get(thread));
            }
        }
        Thread.sleep(1000);
    }
}
