import java.lang.ref.WeakReference;
import java.lang.reflect.Field;
import java.nio.file.Path;
import java.util.ArrayList;
import java.util.List;
import java.util.concurrent.atomic.AtomicReference;

public class WeakProbe {
    public static void main(String[] args) throws Exception {
        List<WeakReference<ClassLoader>> refs = new ArrayList<>();
        TextDaemon daemon = new TextDaemon(Path.of(args[0]), 4);
        for (int generation = 1; generation <= 2; generation++) {
            daemon.reload(generation);
            daemon.processBatch(List.of("alpha beta gamma", "alpha beta gamma", "alpha beta gamma", "alpha beta gamma"));
